import {simplifyPolyline} from './geometry.js';
export function traceOuterBorder(mask,w,h,cfg){if(!cfg.enabled)return null;const pts=[];for(let y=1;y<h-1;y++)for(let x=1;x<w-1;x++){const i=y*w+x;if(mask[i]&&(!mask[i-1]||!mask[i+1]||!mask[i-w]||!mask[i+w]))pts.push({x,y})}const path=simplifyPolyline(pts,cfg.simplification||2);return {id:'outer_border',name:'Outer silhouette border',type:'border',color:cfg.color,strokeWidth:cfg.strokeWidth,visible:true,polylines:[path],segments:[],stats:{points:path.length},note:'Fallback: border is a thick centered stroke over sampled silhouette; future version can use true outward offset.'}}
